mapper.select:
SELECT R.SEQ, R.EVS_TYPE, R.RESUME_NAME, R.REMARK, R.EVS_CYCLE, GET_GLOBAL_NAME(R.EVS_CYCLE, #{lang, jdbcType=VARCHAR}) AS EVS_CYCLE_NAME, R.EVS_YEAR, R.EVS_MONTH, GET_GLOBAL_NAME(R.EVS_MONTH, #{lang, jdbcType=VARCHAR}) AS EVS_MONTH_NAME, TO_CHAR(R.STANDARD_DATE, 'DD/MM/YYYY') AS STANDARD_DATE, R.EVS_START_DATE, R.EVS_END_DATE, R.ACTIVITY, CASE R.ACTIVITY WHEN '2' THEN 'Chuẩn bị' WHEN '3' THEN 'Tiến hành' WHEN '4' THEN 'Hoàn thành' WHEN '1' THEN 'Hoàn thành' ELSE R.ACTIVITY END AS ACTIVITY_NAME, R.EVS_LEVEL, GET_GLOBAL_NAME(R.EVS_LEVEL, #{lang, jdbcType=VARCHAR}) AS EVS_LEVEL_NAME, R.COPY_OBJECT, R.TARGET_LEVEL, TO_CHAR(R.ORDER_NO) AS ORDER_NO, TO_CHAR(R.CREATE_DATE, 'DD/MM/YYYY HH24:MI') AS CREATE_DATE, R.CREATED_BY, TO_CHAR(R.UPDATE_DATE, 'DD/MM/YYYY HH24:MI') AS UPDATE_DATE, R.UPDATED_BY FROM EVS_RESUME_INFO R WHERE R.CPNY_ID = #{cpnyId, jdbcType=VARCHAR} AND R.ACTIVITY != '0'
AND R.EVS_YEAR = #{yearSearch, jdbcType=VARCHAR}
AND R.EVS_TYPE = #{evsType, jdbcType=VARCHAR}
AND R.EVS_CYCLE = #{cycleSearch, jdbcType=VARCHAR}
ORDER BY R.ORDER_NO, R.EVS_YEAR DESC, R.STANDARD_DATE DESC

mapper.update:
UPDATE EVS_RESUME_INFO SET RESUME_NAME = #{resumeName, jdbcType=VARCHAR}, REMARK = #{remark, jdbcType=VARCHAR}, EVS_CYCLE = #{evsCycle, jdbcType=VARCHAR}, EVS_YEAR = #{evsYear, jdbcType=VARCHAR}, EVS_MONTH = #{evsMonth, jdbcType=VARCHAR}, STANDARD_DATE =
TO_DATE(#{standardDate, jdbcType=VARCHAR}, 'DD/MM/YYYY')
NULL , EVS_START_DATE = #{evsStartDate, jdbcType=VARCHAR}, EVS_END_DATE = #{evsEndDate, jdbcType=VARCHAR}, EVS_LEVEL = #{evsLevel, jdbcType=VARCHAR}, COPY_OBJECT = #{copyObject, jdbcType=VARCHAR}, TARGET_LEVEL = #{targetLevel, jdbcType=VARCHAR}, ORDER_NO = #{orderNo, jdbcType=VARCHAR} ORDER_NO , UPDATED_BY = #{adminID, jdbcType=VARCHAR}, UPDATED_IP = #{adminIP, jdbcType=VARCHAR}, UPDATE_DATE = SYSDATE WHERE SEQ = #{seq, jdbcType=VARCHAR} AND CPNY_ID = #{cpnyId, jdbcType=VARCHAR}

